        text = open(p, 'r', encoding='utf-8', errors='ignore').read()
    except Exception:
        continue
    if not text.strip():
        continue
    total = len(text)
    ascii_ratio = sum(1 for ch in text if ord(ch) < 128) / max(1, total)
    words = re.findall(r'[A-Za-z]+', text)
    lw = [w.lower() for w in words]
    stop_count = sum(1 for w in lw if w in english_stopwords)
    word_count = len(lw)
    # English if ASCII reasonably high and enough English stopwords present
    is_english = (ascii_ratio > 0.80 and stop_count >= max(10, 0.03 * max(1, word_count)))
    if is_english:
        eng_paths.append(p)
open('/app/eng_docs.txt', 'w', encoding='utf-8').write('\n'.join(eng_paths) + ('\n' if eng_paths else ''))
print('English docs selected:', len(eng_paths))
for p in eng_paths:
    print('ENG:', p)
