import re
from collections import Counter
ENG_PATHS_FILE = '/app/eng_docs.txt'
TOKENS_FILE = '/app/tokens.txt'
MERGES_FILE = '/app/merges.txt'
EOW = '<|eow|>'
MAX_VOCAB = 1000
paths = [line.strip() for line in open(ENG_PATHS_FILE, 'r', encoding='utf-8') if line.strip()]
texts = []
for p in paths:
    try:
        texts.append(open(p, 'r', encoding='utf-8', errors='ignore').read())
    except Exception:
        pass
word_units = []
word_re = re.compile(r"[A-Za-z]+|[^A-Za-z\s]")
for text in texts:
    for m in word_re.finditer(text):
        unit = m.group(0)
        symbols = list(unit) + [EOW]
        word_units.append(symbols)
# Initialize vocab
vocab = set([EOW])
for w in word_units:
    for s in w:
        if s != EOW:
            vocab.add(s)
from collections import Counter
def get_pair_freqs(words):
    freqs = Counter()
    for w in words:
        for i in range(len(w) - 1):
            freqs[(w[i], w[i+1])] += 1
    return freqs
def apply_merge(words, a, b):
    merged = a + b
    new_words = []
    for w in words:
        i = 0
        nw = []
        while i < len(w):
            if i < len(w)-1 and w[i]==a and w[i+1]==b:
                nw.append(merged)
                i += 2
            else:
                nw.append(w[i])
                i += 1
        new_words.append(nw)
    return new_words, merged
merges = []
while len(vocab) < MAX_VOCAB:
    pair_freqs = get_pair_freqs(word_units)
    if not pair_freqs:
        break
    maxf = max(pair_freqs.values())
    cands = [p for p, c in pair_freqs.items() if c == maxf]
    cands.sort(key=lambda p: (p[0], p[1]))
    a,b = cands[0]
    word_units, merged = apply_merge(word_units, a, b)
    if merged not in vocab:
        vocab.add(merged)
    merges.append((a,b))
# Write outputs
with open(TOKENS_FILE, 'w', encoding='utf-8') as f:
    for t in sorted(vocab):
        f.write(t+'\n')
with open(MERGES_FILE, 'w', encoding='utf-8') as f:
    for a,b in merges:
        f.write(f"{a} {b}\n")
print(f"Vocab size: {len(vocab)}; Merges: {len(merges)}")
